"use client";

import { useState, useEffect, useCallback } from "react";
import Link from "next/link";
import { testQuestions } from "@/data/testQuestions";

type Phase = "intro" | "test" | "solutions";

const TOTAL_SECONDS = 3 * 60 * 60;

function formatTime(s: number): string {
  const h = Math.floor(s / 3600);
  const m = Math.floor((s % 3600) / 60);
  const sec = s % 60;
  if (h > 0)
    return `${h}:${String(m).padStart(2, "0")}:${String(sec).padStart(2, "0")}`;
  return `${String(m).padStart(2, "0")}:${String(sec).padStart(2, "0")}`;
}

function NavBar() {
  return (
    <nav className="sticky top-0 z-50 bg-black border-b border-white/10">
      <div className="max-w-7xl mx-auto px-4">
        <div className="flex items-center justify-between h-14">
          <Link href="/" className="flex items-center gap-2.5 shrink-0">
            <span className="flex items-center justify-center w-8 h-8 rounded-lg bg-white/25 text-white font-black text-sm">
              מ
            </span>
            <span className="font-bold text-white text-sm md:text-base">
              בגרות מתמטיקה 5 יח״ל
            </span>
          </Link>
          <Link href="/" className="text-white/60 hover:text-white text-sm transition-colors">
            ← חזרה לדף הבית
          </Link>
        </div>
      </div>
    </nav>
  );
}

export default function TestClient() {
  const [phase, setPhase] = useState<Phase>("intro");
  const [timeLeft, setTimeLeft] = useState(TOTAL_SECONDS);
  const [timerActive, setTimerActive] = useState(false);
  // key = `${questionId}-${label}`, value = open/closed
  const [openSolutions, setOpenSolutions] = useState<Set<string>>(new Set());

  const endTest = useCallback(() => {
    setTimerActive(false);
    setPhase("solutions");
  }, []);

  useEffect(() => {
    if (!timerActive) return;
    const id = setInterval(() => setTimeLeft((t) => Math.max(0, t - 1)), 1000);
    return () => clearInterval(id);
  }, [timerActive]);

  useEffect(() => {
    if (timerActive && timeLeft === 0) endTest();
  }, [timeLeft, timerActive, endTest]);

  function startTest() {
    setTimeLeft(TOTAL_SECONDS);
    setTimerActive(true);
    setOpenSolutions(new Set());
    setPhase("test");
  }

  function restart() {
    setPhase("intro");
    setTimeLeft(TOTAL_SECONDS);
    setTimerActive(false);
    setOpenSolutions(new Set());
  }

  function toggleSolution(key: string) {
    setOpenSolutions((prev) => {
      const next = new Set(prev);
      if (next.has(key)) next.delete(key);
      else next.add(key);
      return next;
    });
  }

  function revealAll() {
    const all = new Set<string>();
    testQuestions.forEach((q) =>
      q.subquestions.forEach((sub) => all.add(`${q.id}-${sub.label}`))
    );
    setOpenSolutions(all);
  }

  const isLowTime = timeLeft < 10 * 60;

  // ══════════════════════════════════════════════════════════════════════════
  // INTRO
  // ══════════════════════════════════════════════════════════════════════════
  if (phase === "intro") {
    return (
      <div className="h-screen bg-white flex flex-col" dir="rtl">
        {/* Top bar */}
        <div className="flex items-center justify-between px-6 md:px-12 h-14 border-b border-slate-100 shrink-0">
          <Link href="/" className="flex items-center gap-2.5">
            <span className="flex items-center justify-center w-8 h-8 rounded-lg bg-black text-white font-black text-sm">מ</span>
            <span className="font-bold text-black text-sm md:text-base">בגרות מתמטיקה 5 יח״ל</span>
          </Link>
          <span className="text-xs font-semibold text-teal-600 border border-teal-200 bg-teal-50 rounded-full px-3 py-1">
            שאלון 581
          </span>
        </div>

        {/* Main — split layout */}
        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">

          {/* Left — big headline */}
          <div className="flex-1 flex flex-col justify-center px-8 md:px-16 py-10 border-b md:border-b-0 md:border-l border-slate-100">
            <p className="text-slate-400 text-sm font-semibold tracking-widest uppercase mb-6">
              מבחן פתוח · כיתה י״א
            </p>
            <h1 className="leading-none font-black text-black tracking-tighter">
              <span className="block text-6xl sm:text-7xl md:text-8xl lg:text-9xl">מבחן</span>
              <span className="block text-6xl sm:text-7xl md:text-8xl lg:text-9xl text-teal-500">מלא</span>
            </h1>
            <p className="text-slate-500 text-base md:text-lg mt-6 leading-relaxed max-w-sm">
              פתור במחברת — בדוק את עצמך לאחר הגשה
            </p>
          </div>

          {/* Right — info + button */}
          <div className="flex flex-col justify-center px-8 md:px-14 py-10 md:w-96 shrink-0">

            {/* Stats */}
            <div className="grid grid-cols-3 gap-3 mb-8">
              {[
                { label: "שאלות", value: "8" },
                { label: "לענות", value: "5" },
                { label: "זמן", value: "3 שע׳" },
              ].map(({ label, value }) => (
                <div key={label} className="border border-slate-200 rounded-xl p-4 text-center">
                  <p className="text-slate-400 text-xs mb-1">{label}</p>
                  <p className="text-2xl font-black text-black">{value}</p>
                </div>
              ))}
            </div>

            {/* Instructions */}
            <div className="space-y-3 mb-10">
              {[
                "יוצגו כל 8 השאלות — בחר/י 5 לפתרון",
                "פתור/י את השאלות במחברת",
                'בסיום — לחץ "הצג פתרון" לבדיקה עצמית',
              ].map((line, i) => (
                <div key={i} className="flex items-start gap-3">
                  <span className="shrink-0 mt-0.5 w-5 h-5 rounded-full bg-black text-white text-xs flex items-center justify-center font-bold">
                    {i + 1}
                  </span>
                  <p className="text-sm text-slate-600 leading-snug">{line}</p>
                </div>
              ))}
            </div>

            <button
              onClick={startTest}
              className="w-full bg-black text-white font-black text-lg py-5 rounded-2xl hover:bg-slate-800 transition-colors tracking-tight"
            >
              התחל מבחן ←
            </button>

            <Link href="/" className="mt-4 text-center text-sm text-slate-400 hover:text-black transition-colors block">
              חזרה לדף הבית
            </Link>
          </div>
        </div>
      </div>
    );
  }

  // ══════════════════════════════════════════════════════════════════════════
  // TEST — all 8 questions displayed, student solves on paper
  // ══════════════════════════════════════════════════════════════════════════
  if (phase === "test") {
    return (
      <div className="min-h-screen bg-slate-50" dir="rtl">
        {/* Sticky timer */}
        <div className="sticky top-0 z-50 bg-black border-b border-white/10">
          <div className="max-w-4xl mx-auto px-4 h-14 flex items-center justify-between">
            <div className={`flex items-center gap-2 font-mono font-bold text-lg ${isLowTime ? "text-red-400" : "text-white"}`}>
              <svg className="w-4 h-4 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <circle cx="12" cy="12" r="10" strokeWidth="2" />
                <path d="M12 6v6l4 2" strokeWidth="2" strokeLinecap="round" />
              </svg>
              {formatTime(timeLeft)}
            </div>
            <span className="text-white/70 text-sm hidden sm:block">ענה/י על 5 שאלות לבחירתך במחברת</span>
            <button
              onClick={endTest}
              className="bg-white text-black font-bold text-sm px-5 py-2 rounded-lg hover:bg-slate-100 transition-colors"
            >
              סיים מבחן
            </button>
          </div>
          {isLowTime && (
            <div className="bg-red-600 text-white text-center text-xs py-1 font-semibold">
              פחות מ-10 דקות נותרו!
            </div>
          )}
        </div>

        {/* Questions */}
        <div className="max-w-4xl mx-auto px-4 py-10 space-y-8">
          {testQuestions.map((q, i) => (
            <div key={q.id} className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6 md:p-8">
              {/* Header */}
              <div className="flex items-center gap-3 mb-5">
                <div className="w-9 h-9 rounded-xl bg-black text-white flex items-center justify-center font-black text-sm shrink-0">
                  {i + 1}
                </div>
                <span className="bg-teal-50 border border-teal-200 text-teal-700 text-xs font-semibold rounded-full px-3 py-1">
                  {q.topic}
                </span>
              </div>

              {/* Main text */}
              <p className="text-black text-base leading-relaxed whitespace-pre-line mb-6 font-medium">
                {q.text}
              </p>

              {/* Sub-questions */}
              <div className="space-y-4 border-t border-slate-100 pt-5">
                {q.subquestions.map((sub) => (
                  <div key={sub.label} className="flex gap-4">
                    <span className="shrink-0 mt-0.5 w-7 h-7 rounded-lg bg-slate-100 flex items-center justify-center text-xs font-bold text-slate-600">
                      {sub.label}
                    </span>
                    <p className="text-black text-sm leading-relaxed whitespace-pre-line">
                      {sub.text}
                    </p>
                  </div>
                ))}
              </div>
            </div>
          ))}

          <div className="text-center pt-4 pb-8">
            <button
              onClick={endTest}
              className="bg-black text-white font-bold px-10 py-4 rounded-xl hover:bg-slate-800 transition-colors text-base"
            >
              סיים וראה פתרונות ←
            </button>
          </div>
        </div>
      </div>
    );
  }

  // ══════════════════════════════════════════════════════════════════════════
  // SOLUTIONS — reveal per sub-question
  // ══════════════════════════════════════════════════════════════════════════
  return (
    <div className="min-h-screen bg-white" dir="rtl">
      <NavBar />

      <div className="max-w-4xl mx-auto px-4 py-12">
        {/* Header */}
        <div className="bg-black text-white rounded-2xl p-8 mb-4 text-center">
          <p className="text-white/60 text-sm mb-2">מבחן הסתיים</p>
          <h2 className="text-3xl md:text-4xl font-black mb-2">מפתח פתרונות</h2>
          <p className="text-white/70 text-sm">לחץ על "הצג פתרון" בכל סעיף לבדיקה עצמית</p>
        </div>

        {/* Reveal all button */}
        <div className="flex justify-end mb-6">
          <button
            onClick={revealAll}
            className="text-sm font-semibold text-teal-700 hover:text-teal-900 underline underline-offset-2 transition-colors"
          >
            הצג את כל הפתרונות
          </button>
        </div>

        {/* Questions + solutions */}
        <div className="space-y-8 mb-10">
          {testQuestions.map((q, i) => (
            <div key={q.id} className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
              {/* Question header */}
              <div className="p-6 md:p-8">
                <div className="flex items-center gap-3 mb-5">
                  <div className="w-9 h-9 rounded-xl bg-black text-white flex items-center justify-center font-black text-sm shrink-0">
                    {i + 1}
                  </div>
                  <span className="bg-teal-50 border border-teal-200 text-teal-700 text-xs font-semibold rounded-full px-3 py-1">
                    {q.topic}
                  </span>
                </div>

                <p className="text-black text-base leading-relaxed whitespace-pre-line font-medium mb-0">
                  {q.text}
                </p>
              </div>

              {/* Sub-questions */}
              <div className="divide-y divide-slate-100">
                {q.subquestions.map((sub) => {
                  const key = `${q.id}-${sub.label}`;
                  const isOpen = openSolutions.has(key);
                  return (
                    <div key={sub.label} className="px-6 md:px-8 py-5">
                      {/* Sub-question text */}
                      <div className="flex gap-4 mb-3">
                        <span className="shrink-0 mt-0.5 w-7 h-7 rounded-lg bg-slate-100 flex items-center justify-center text-xs font-bold text-slate-600">
                          {sub.label}
                        </span>
                        <p className="text-black text-sm leading-relaxed whitespace-pre-line flex-1">
                          {sub.text}
                        </p>
                      </div>

                      {/* Toggle button */}
                      <div className="mr-11">
                        <button
                          onClick={() => toggleSolution(key)}
                          className={`text-xs font-bold px-4 py-1.5 rounded-lg border transition-all ${
                            isOpen
                              ? "bg-green-50 border-green-300 text-green-700"
                              : "bg-slate-50 border-slate-300 text-slate-600 hover:border-slate-400"
                          }`}
                        >
                          {isOpen ? "▲ הסתר פתרון" : "▼ הצג פתרון"}
                        </button>
                      </div>

                      {/* Solution */}
                      {isOpen && (
                        <div className="mr-11 mt-3 bg-green-50 border border-green-200 rounded-xl p-4">
                          <p className="text-green-900 text-sm leading-loose whitespace-pre-line font-mono">
                            {sub.solution}
                          </p>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            </div>
          ))}
        </div>

        {/* Actions */}
        <div className="flex gap-3 justify-center flex-wrap">
          <button
            onClick={restart}
            className="bg-black text-white font-bold px-8 py-3 rounded-xl hover:bg-slate-800 transition-colors"
          >
            מבחן חדש
          </button>
          <Link
            href="/"
            className="border border-slate-300 text-black font-bold px-8 py-3 rounded-xl hover:border-slate-500 transition-colors"
          >
            חזרה לדף הבית
          </Link>
        </div>
      </div>
    </div>
  );
}
